import React, { useState, useEffect } from 'react';
import { Wallet, TrendingDown, Trash2, History, RefreshCw } from 'lucide-react';

// --- TYPES ---
interface Transaction {
  id: string;
  amount: number;
  description: string;
  date: string;
}

interface BudgetState {
  balance: number;
  lastLoginDate: string;
  transactions: Transaction[];
}

const STORAGE_KEY = 'daily_budget_pwa_v2';
const DAILY_AMOUNT = 30;

function App() {
  const [balance, setBalance] = useState<number>(0);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [amount, setAmount] = useState<string>('');
  const [description, setDescription] = useState<string>('');
  const [addedToday, setAddedToday] = useState<number>(0);
  const [isLoaded, setIsLoaded] = useState(false);

  // --- UTILS ---
  const getTodayString = () => new Date().toISOString().split('T')[0];

  const formatCurrency = (val: number) => 
    new Intl.NumberFormat('fr-FR', { style: 'currency', currency: 'EUR' }).format(val);

  // --- LOGIC ---
  useEffect(() => {
    try {
      const stored = localStorage.getItem(STORAGE_KEY);
      const today = getTodayString();

      let newState: BudgetState;

      if (stored) {
        const parsed: BudgetState = JSON.parse(stored);
        const lastDate = parsed.lastLoginDate;

        // Simple logic: if stored date is strictly less than today, add money.
        // For more robust logic, we parse dates.
        const dLast = new Date(lastDate);
        const dNow = new Date(today);

        let newMoney = 0;

        if (lastDate < today) {
          // Difference in days
          const diffTime = Math.abs(dNow.getTime() - dLast.getTime());
          const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
          newMoney = diffDays * DAILY_AMOUNT;
        }

        newState = {
          balance: parsed.balance + newMoney,
          transactions: parsed.transactions || [],
          lastLoginDate: today
        };
        setAddedToday(newMoney);
      } else {
        newState = {
          balance: DAILY_AMOUNT,
          transactions: [],
          lastLoginDate: today
        };
        setAddedToday(DAILY_AMOUNT);
      }

      setBalance(newState.balance);
      setTransactions(newState.transactions);
      localStorage.setItem(STORAGE_KEY, JSON.stringify(newState));
    } catch (err) {
      console.error("Error loading data", err);
    } finally {
      setIsLoaded(true);
    }
  }, []);

  const save = (newBalance: number, newTransactions: Transaction[]) => {
    const today = getTodayString();
    const state: BudgetState = {
      balance: newBalance,
      transactions: newTransactions,
      lastLoginDate: today
    };
    localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
    setBalance(newBalance);
    setTransactions(newTransactions);
  };

  const handleAddExpense = (e: React.FormEvent) => {
    e.preventDefault();
    const val = parseFloat(amount.replace(',', '.'));
    if (!val || val <= 0) return;

    const newTx: Transaction = {
      id: Math.random().toString(36).substr(2, 9),
      amount: val,
      description: description || 'Dépense diverse',
      date: new Date().toISOString()
    };

    const updatedTx = [newTx, ...transactions];
    const updatedBalance = balance - val;

    save(updatedBalance, updatedTx);
    setAmount('');
    setDescription('');
  };

  const handleDelete = (id: string) => {
    const tx = transactions.find(t => t.id === id);
    if (!tx) return;

    const updatedTx = transactions.filter(t => t.id !== id);
    const updatedBalance = balance + tx.amount;
    save(updatedBalance, updatedTx);
  };

  const handleReset = () => {
    if (confirm('Voulez-vous vraiment tout effacer ?')) {
      localStorage.removeItem(STORAGE_KEY);
      window.location.reload();
    }
  };

  if (!isLoaded) return <div className="loading">Chargement...</div>;

  return (
    <div className="app-container">
      {/* HEADER */}
      <header className="header">
        <div className="header-title-row">
          <div className="logo-bg">
            <Wallet size={24} color="#10b981" />
          </div>
          <h1 className="app-title">Budget Daily</h1>
        </div>
        <p className="app-subtitle">Gérez votre budget quotidien.</p>
      </header>

      {/* BALANCE CARD */}
      <div className="card balance-card">
        <div className="glow-effect"></div>
        <div className="balance-label">Solde Actuel</div>
        <div className={`balance-amount ${balance < 0 ? 'negative' : ''}`}>
          {formatCurrency(balance)}
        </div>
        {addedToday > 0 && (
          <div className="pill-badge">
            +{formatCurrency(addedToday)} ajoutés ce matin
          </div>
        )}
      </div>

      {/* INPUT CARD */}
      <div className="card">
        <div className="card-header">
          <h2 className="card-title">Nouvelle Dépense</h2>
        </div>
        <div className="card-body">
          <form onSubmit={handleAddExpense} className="form-stack">
            <div className="input-group">
              <label className="input-label">Montant (€)</label>
              <input 
                className="text-input"
                type="number" 
                inputMode="decimal"
                step="0.01"
                value={amount}
                onChange={e => setAmount(e.target.value)}
                placeholder="0.00"
                required 
                autoFocus
              />
            </div>
            <div className="input-group">
              <label className="input-label">Description (Optionnel)</label>
              <input 
                className="text-input"
                type="text" 
                value={description}
                onChange={e => setDescription(e.target.value)}
                placeholder="Ex: Café, Transport..."
              />
            </div>
            <button type="submit" className="btn btn-primary-danger">
              <TrendingDown size={20} />
              Déduire du budget
            </button>
          </form>
        </div>
      </div>

      {/* HISTORY CARD */}
      <div className="card">
        <div className="card-body">
          <div className="history-header-row">
            <div className="history-title">
              <History size={18} className="text-muted" />
              <span>Historique</span>
            </div>
            <span className="history-count">{transactions.length} transactions</span>
          </div>

          <div className="tx-list">
            {transactions.length === 0 ? (
              <div className="empty-state">Aucune dépense récente.</div>
            ) : (
              transactions.map(tx => (
                <div key={tx.id} className="tx-item">
                  <div className="tx-left">
                    <span className="tx-desc">{tx.description}</span>
                    <span className="tx-date">
                      {new Date(tx.date).toLocaleDateString('fr-FR', {
                        day: 'numeric', month: 'short', hour: '2-digit', minute:'2-digit'
                      })}
                    </span>
                  </div>
                  <div className="tx-right">
                    <span className="tx-amount">-{formatCurrency(tx.amount)}</span>
                    <button 
                      className="btn-delete"
                      onClick={() => handleDelete(tx.id)}
                      aria-label="Supprimer"
                    >
                      <Trash2 size={16} />
                    </button>
                  </div>
                </div>
              ))
            )}
          </div>
        </div>
      </div>

      {/* FOOTER */}
      <button onClick={handleReset} className="reset-link">
        <RefreshCw size={12} />
        Réinitialiser l'application
      </button>
    </div>
  );
}

export default App;

