import { useState, useEffect } from 'react';

export interface Transaction {
  id: string;
  amount: number;
  description: string;
  date: string;
}

interface BudgetState {
  balance: number;
  lastLoginDate: string;
  transactions: Transaction[];
}

const STORAGE_KEY = 'mon_budget_daily_v2';
const DAILY_ALLOWANCE = 30;

export const useBudget = () => {
  const [balance, setBalance] = useState<number>(0);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [isLoaded, setIsLoaded] = useState(false);
  const [dailyAdded, setDailyAdded] = useState<number>(0);

  const getTodayString = () => new Date().toISOString().split('T')[0];

  useEffect(() => {
    try {
      const stored = localStorage.getItem(STORAGE_KEY);
      const today = getTodayString();
      let newState: BudgetState;

      if (stored) {
        const parsed: BudgetState = JSON.parse(stored);
        const lastDate = parsed.lastLoginDate;

        let addedAmount = 0;

        // Si la dernière connexion date d'avant aujourd'hui (strictement)
        if (lastDate < today) {
          const dLast = new Date(lastDate);
          const dNow = new Date(today);
          const diffTime = Math.abs(dNow.getTime() - dLast.getTime());
          const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

          addedAmount = diffDays * DAILY_ALLOWANCE;
        }

        newState = {
          balance: parsed.balance + addedAmount,
          transactions: parsed.transactions || [],
          lastLoginDate: today
        };
        setDailyAdded(addedAmount);
      } else {
        // Premier lancement
        newState = {
          balance: DAILY_ALLOWANCE,
          transactions: [],
          lastLoginDate: today
        };
        setDailyAdded(DAILY_ALLOWANCE);
      }

      // Mise à jour du state et du storage
      setBalance(newState.balance);
      setTransactions(newState.transactions);
      localStorage.setItem(STORAGE_KEY, JSON.stringify(newState));
    } catch (e) {
      console.error("Erreur chargement budget", e);
    } finally {
      setIsLoaded(true);
    }
  }, []);

  const save = (newBalance: number, newTransactions: Transaction[]) => {
    const today = getTodayString();
    const state: BudgetState = {
      balance: newBalance,
      transactions: newTransactions,
      lastLoginDate: today
    };
    localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
    setBalance(newBalance);
    setTransactions(newTransactions);
  };

  const addExpense = (amount: number, description: string) => {
    const newTx: Transaction = {
      id: Math.random().toString(36).substring(2),
      amount,
      description: description || 'Dépense',
      date: new Date().toISOString()
    };
    const updatedTx = [newTx, ...transactions];
    const updatedBalance = balance - amount;
    save(updatedBalance, updatedTx);
  };

  const deleteTransaction = (id: string) => {
    const tx = transactions.find(t => t.id === id);
    if (!tx) return;
    const updatedTx = transactions.filter(t => t.id !== id);
    const updatedBalance = balance + tx.amount;
    save(updatedBalance, updatedTx);
  };

  const resetData = () => {
    localStorage.removeItem(STORAGE_KEY);
    window.location.reload();
  };

  return {
    balance,
    transactions,
    isLoaded,
    dailyAdded,
    addExpense,
    deleteTransaction,
    resetData
  };
};

